{\\rtf1\\ansi\\deff0{\\fonttbl{\\f0 \\fswiss Helvetica;}}
{\\pard \\ql \\f0 \\sa180 \\li0 \\fi0 \\b ResolveLink Callback\\par}
{\\pard \\ql \\f0 \\sa180 \\li0 \\fi0 A polling script that monitors the ResolveLink server for pending REAPER import jobs. When a job arrives, it automatically creates a REAPER project with audio clips from DaVinci Resolve.\\par}
{\\pard \\ql \\f0 \\sa180 \\li0 \\fi0 \\b Requirements:\\par}
{\\pard \\ql \\f0 \\sa180 \\li0 \\fi0 - ResolveLink server running at http://127.0.0.1:3030\\par}
{\\pard \\ql \\f0 \\sa180 \\li0 \\fi0 - curl available in PATH\\par}
{\\pard \\ql \\f0 \\sa180 \\li0 \\fi0 \\b Usage:\\par}
{\\pard \\ql \\f0 \\sa180 \\li0 \\fi0 Run from Actions > Show action list > Load, or assign to a toolbar button. Press the button again to stop polling.\\par}
}

{\\rtf1\\ansi\\deff0{\\fonttbl{\\f0 \\fswiss Helvetica;}}
{\\pard \\ql \\f0 \\sa180 \\li0 \\fi0 \\b \\fs36 ResolveLink\\par}
{\\pard \\ql \\f0 \\sa180 \\li0 \\fi0 Bridge between DaVinci Resolve, After Effects, and REAPER.\\par}
{\\pard \\ql \\f0 \\sa180 \\li0 \\fi0 This repository contains REAPER scripts for the ResolveLink workflow.\\par}
}
